PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE profile (
    id              INTEGER PRIMARY KEY CHECK (id = 1),  
    name            TEXT    NOT NULL,
    headline        TEXT,
    skills          TEXT,   
    interests       TEXT,   
    target_locations TEXT,  
    experience      TEXT,   
    updated_at      TEXT    NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now'))
, stage      TEXT, priorities TEXT, cv_text TEXT);
CREATE TABLE cv_variants (
    id              INTEGER PRIMARY KEY AUTOINCREMENT,
    opportunity_id  INTEGER NOT NULL REFERENCES opportunities (id) ON DELETE CASCADE,
    label           TEXT    NOT NULL DEFAULT 'default',  
    storage_key     TEXT    NOT NULL,                    
    created_at      TEXT    NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
    UNIQUE (opportunity_id, label)
);
CREATE TABLE actions (
    id              INTEGER PRIMARY KEY AUTOINCREMENT,
    opportunity_id  INTEGER NOT NULL REFERENCES opportunities (id) ON DELETE CASCADE,
    draft_id        INTEGER          REFERENCES drafts (id) ON DELETE SET NULL,
    kind            TEXT    NOT NULL CHECK (kind IN ('send_email', 'linkedin_post', 'other')),
    status          TEXT    NOT NULL DEFAULT 'pending'
                            CHECK (status IN ('pending', 'approved', 'sent', 'posted', 'failed')),
    result          TEXT,              
    queued_at       TEXT    NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
    approved_at     TEXT,
    executed_at     TEXT
);
CREATE TABLE sources (
    id       INTEGER PRIMARY KEY AUTOINCREMENT,
    ats_type TEXT    NOT NULL CHECK (ats_type IN ('greenhouse', 'lever')),
    token    TEXT    NOT NULL,
    label    TEXT    NOT NULL,
    active   INTEGER NOT NULL DEFAULT 1 CHECK (active IN (0, 1)),
    added_at TEXT    NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now'))
, event_type TEXT);
CREATE TABLE IF NOT EXISTS "opportunities" (
    id              INTEGER PRIMARY KEY AUTOINCREMENT,
    type            TEXT    NOT NULL CHECK (type IN ('internship', 'conference', 'ngo', 'certificate')),
    title           TEXT    NOT NULL,
    organization    TEXT    NOT NULL,
    source          TEXT    NOT NULL,
    url             TEXT,
    location        TEXT,
    deadline        TEXT,
    description     TEXT,
    fit_score       REAL    CHECK (fit_score IS NULL OR (fit_score >= 0 AND fit_score <= 100)),
    fit_reason      TEXT,
    status          TEXT    NOT NULL DEFAULT 'new'
                            CHECK (status IN ('new', 'shortlisted', 'applied', 'rejected', 'archived')),
    dedup_hash      TEXT    NOT NULL UNIQUE,
    discovered_at   TEXT    NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now'))
, region TEXT DEFAULT 'unknown');
CREATE TABLE IF NOT EXISTS "drafts" (
    id              INTEGER PRIMARY KEY AUTOINCREMENT,
    opportunity_id  INTEGER NOT NULL REFERENCES opportunities (id) ON DELETE CASCADE,
    kind            TEXT    NOT NULL DEFAULT 'application_email',
    subject         TEXT,
    body            TEXT    NOT NULL,
    status          TEXT    NOT NULL DEFAULT 'pending'
                            CHECK (status IN ('pending', 'approved', 'dismissed')),
    created_at      TEXT    NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now'))
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_actions_status       ON actions (status);
CREATE INDEX idx_actions_opportunity  ON actions (opportunity_id);
CREATE UNIQUE INDEX idx_sources_ats_token ON sources (ats_type, token);
CREATE INDEX idx_opportunities_type     ON opportunities (type);
CREATE INDEX idx_opportunities_status   ON opportunities (status);
CREATE INDEX idx_opportunities_deadline ON opportunities (deadline);
CREATE INDEX idx_opportunities_fit      ON opportunities (fit_score);
CREATE INDEX idx_drafts_opportunity ON drafts (opportunity_id);
CREATE INDEX idx_drafts_status      ON drafts (status);
