INSERT INTO "opportunities" ("id","type","title","organization","source","url","location","deadline","description","fit_score","fit_reason","status","dedup_hash","discovered_at","region") VALUES(27,'internship','Staff Software Engineer - Database Engine Internals','Databricks','greenhouse','https://databricks.com/company/careers/open-positions/job?gh_jid=8012818002','Belgrade, Serbia',NULL,replace('<p> </p>\n<p>P-1416</p>\n<p>Our mission at Databricks is to radically simplify the whole data lifecycle from ingestion to ETL, BI, and all the way up to ML/AI with a unified platform. To achieve this goal, we believe the data warehouse architecture as we know it today will be replaced by a new architectural pattern, Lakehouse (<a href= http://cidrdb.org/cidr2021/papers/cidr2021_paper17.pdf >CIDR 2021 paper</a>), open platforms that unify data warehousing and advanced analytics. This new architecture will help address several major challenges, including data staleness, reliability, total cost of ownership, data lock-in, and limited use-case support.</p>\n<p>To achieve this vision, Databricks is building the next generation (decoupled) query engine and structured storage system that can outperform specialized data warehouses in relational query performance. Yet we will retain the expressiveness and robustness of general purpose systems such as Apache Spark™ to support diverse workloads ranging from ETL to data science. You will be part of this multi-year journey.</p>\n<p>As part of this team, you will design these next-generation systems that leapfrog state-of-the-art within the following areas:</p>\n<ul>\n<li>Query compilation and optimization</li>\n<li>Distributed query execution and scheduling</li>\n<li>Vectorized execution engine</li>\n<li>Data security</li>\n<li>Resource management</li>\n<li>Transaction coordination</li>\n<li>Efficient storage structures (encodings, indexes)</li>\n<li>Automatic physical data optimization</li>\n</ul>\n<p><strong>The responsibilities you will have:</strong></p>\n<ul>\n<li>Drive requirements clarity and design decisions for ambiguous problems</li>\n<li>Produce technical design documents and project plans</li>\n<li>Develop new features</li>\n<li>Mentor more junior engineers</li>\n<li>Test and rollout to production, monitoring.</li>\n</ul>\n<p><strong>What we look for:</strong></p>\n<ul>\n<li>A passion for database systems, storage systems, distributed systems, language design, or performance optimization</li>\n<li>Are comfortable working towards a multi-year vision with incremental deliverables</li>\n<li>Be customer-oriented and focused on having an impact</li>\n<li>7+ years of experience working in a related system</li>\n<li>Optional: PhD in databases or distributed systems</li>\n</ul><div class= content-conclusion ><p><strong>About Databricks</strong></p>\n<p><span style= font-family: arial, sans-serif; >Databricks is the data and AI company. More than 10,000 organizations worldwide — including Comcast, Condé Nast, Grammarly, and over 50% of the Fortune 500 — rely on the Databricks Data Intelligence Platform to unify and democratize data, analytics and AI. Databricks is headquartered in San Francisco, with offices around the globe and was founded by the original creators of Lakehouse, Apache Spark™, Delta Lake and MLflow. To learn more, follow Databricks on <span style= color: rgb(255, 54, 33); ><a style= color: rgb(255, 54, 33);  href= https://twitter.com/databricks  target= _blank  data-saferedirecturl= https://www.google.com/url?q=https://twitter.com/databricks source=gmail ust=1700237575733000 usg=AOvVaw03FL8fJvOD97ytN02f5G2C >Twitter</a>, <a style= color: rgb(255, 54, 33);  href= https://www.linkedin.com/company/databricks  target= _blank  data-saferedirecturl= https://www.google.com/url?q=https://www.linkedin.com/company/databricks source=gmail ust=1700237575733000 usg=AOvVaw15dLk3q8VxTfHEgCUg7NSt >LinkedIn</a> <span style= color: rgb(0, 0, 0); >and</span> <a style= color: rgb(255, 54, 33);  href= https://www.facebook.com/databricksinc  target= _blank  data-saferedirecturl= https://www.google.com/url?q=https://www.facebook.com/databricksinc source=gmail ust=1700237575733000 usg=AOvVaw39EcncitnlqV72EG2-RqXJ >Facebook</a></span>.<br><br><strong>Benefits<br><br></strong></span>At Databricks, we strive to provide comprehensive benefits and perks that meet the needs of all of our employees. For specific details on the benefits offered in your region click <a href= https://docs.google.com/document/d/154un3e8Xav4BceOSlcYFZRGEuQI54xMxVydRwQn54eQ/edit?usp=sharing >here</a>.<br><br></p>\n<p><strong>Our Commitment to Diversity and Inclusion</strong></p>\n<p>At Databricks, we are committed to fostering a diverse and inclusive culture where everyone can excel. We take great care to ensure that our hiring practices are inclusive and meet equal employment opportunity standards. Individuals looking for employment at Databricks are considered without regard to age, color, disability, ethnicity, family or marital status, gender identity or expression, language, national origin, physical and mental ability, political affiliation, race, religion, sexual orientation, socio-economic status, veteran status, and other protected characteristics.</p>\n<p><strong>Compliance</strong></p>\n<p><strong><span style= font-weight: 400; >If access to export-controlled technology or source code is required for performance of job duties, it is within Employer s discretion whether to apply for a U.S. government license for such positions, and Employer may decline to proceed with an applicant on this basis alone.</span></strong></p></div>','\n',char(10)),50,'entry-level + senior (penalized) + CS/tech + internship','new','a2f3ec29c59eada5ac9dc090c15cb933ededf8e34875c8e67610ca8e15c30b85','2026-06-02T06:56:13Z','global');
INSERT INTO "opportunities" ("id","type","title","organization","source","url","location","deadline","description","fit_score","fit_reason","status","dedup_hash","discovered_at","region") VALUES(28,'internship','Communications Intern, LATAM','Airbnb','greenhouse','https://careers.airbnb.com/positions/7900153?gh_jid=7900153','São Paulo, Brazil',NULL,replace('<div class= content-intro ><p><span style= font-family: helvetica, arial, sans-serif; font-size: 12pt; >Airbnb was born in 2007 when two hosts welcomed three guests to their San Francisco home, and has since grown to over 5 million hosts who have welcomed over 2 billion guest arrivals in almost every country across the globe. Every day, hosts offer unique stays and experiences that make it possible for guests to connect with communities in a more authentic way.</span></p></div><p> </p>\n<p><strong>The community you will join:</strong></p>\n<p>Airbnb is seeking a Communications Intern to join the LATAM Communications team in Brazil for a 12-month internship.</p>\n<p>The Communications Team at Airbnb is responsible for telling the Airbnb story around the world. Whether briefing press on inspiring travel trends, highlighting unique experiences led by local hosts, or explaining how travel on our platform benefits families and communities, we are the voice of Airbnb on a broad range of topics. We’re a fast-paced, high-energy team with a passion for people, places, and storytelling. If you’d like to be part of one of the world’s most dynamic communications teams, we’d love to hear your story.</p>\n<p> </p>\n<p><strong>The difference you will make:</strong></p>\n<p>You’ll support the Brazil Communications team on high-impact, high-visibility initiatives that shape Airbnb’s reputation in the region. From supporting travel campaigns to contributing to the launch of major reports, projects and influencer programs, you ll gain hands-on experience working with world-class communications professionals and PR agencies.</p>\n<p>You will be integrated into a team of passionate communicators and storytellers, and will work closely with cross-functional partners including Business, Legal and Policy. Your work will directly contribute to elevating Airbnb’s brand and voice throughout Brazil. This includes: </p>\n<ul>\n<li>Supporting the team in developing and editing internal and external materials such as story pitches, op-eds, Q As, talking points, and presentations.</li>\n<li>Partnering with the Brazil Communications team, from Corporate   Policy as well as Consumer   Product, and PR and influencer agencies to organize media events, press trips, and reporter engagement.</li>\n<li>Following up on key deliverables and campaign trackers to ensure timely execution.</li>\n<li>Researching and identifying new media contacts, influencers, and local outlets.</li>\n<li>Monitoring political, arts, entertainment, and travel trends to help shape campaigns.</li>\n<li>Learning how to build strategic communications plans that reflect Airbnb’s mission and local impact.</li>\n</ul>\n<p> </p>\n<p><strong>The intern experience:</strong></p>\n<p>As an intern, you’ll be integrated into a team where you’ll contribute to challenging projects. Your manager, team, and our incredible employee community will strive to be superhosts to you during the internship. We provide the support, mentorship, fun, and real world experience needed to accelerate your learning and make a real impact on our product, as Airbnb revolutionizes connection, belonging, and travel. You can expect to:</p>\n<ul>\n<li>Collaborate with multiple team members to achieve project milestones.</li>\n<li>Communicate with stakeholders across different teams to provide project updates</li>\n<li>Seek and provide feedback throughout the internship.</li>\n<li>Actively participate in and contribute to the Communications team and broader Airbnb community.</li>\n</ul>\n<p> </p>\n<p><strong>Your expertise:</strong></p>\n<p><em>Currently enrolled in a degree or graduate-level program in Communications, Public Relations or Journalism.</em><em>Bilingual in Portuguese and English (verbal and written fluency required).</em><em>Strong writing and storytelling skills, with a passion for communications and media.</em><em>Experience through coursework, internships, blogging, student publications, or relevant volunteer work.</em><em>Familiarity with Google Suite and Microsoft Office (especially for presentations and content drafting).</em><em>Understanding of social media platforms and digital communications metrics is a plus.</em><em>Enthusiastic, self-starter with strong organizational skills and attention to detail.</em><em>Passion for Airbnb’s mission and belief in the power of travel to create belonging.</em><br><br></p>\n<p><strong>Your location:</strong></p>\n<p>This position is hybrid. You must be based in São Paulo and have work authorization for Brazil to be eligible.</p>\n<p> </p>\n<p><strong>Our commitment to inclusion   belonging:</strong></p>\n<p>Airbnb is committed to working with the broadest talent pool possible. We believe diverse ideas foster innovation and engagement, and allow us to attract creatively-led people, and to develop the best products, services and solutions. All qualified individuals are encouraged to apply.</p>\n<p>We strive to also provide a disability inclusive application and interview process. If you are a candidate with a disability and require reasonable accommodation in order to submit an application, please contact us at: reasonableaccommodations@airbnb.com. Please include your full name, the role you’re applying for and the accommodation necessary to assist you with the recruiting process. </p>\n<p>We ask that you only reach out to us if you are a candidate whose disability prevents you from being able to complete our online application.</p>\n<p><br><br></p>\n<p><strong>Please submit all application materials in English.</strong></p><div class= content-pay-transparency ><div class= pay-input ><div class= description ><p><span style= font-size: 16px; ><strong><span style= font-family: arial, helvetica, sans-serif; color: rgb(0, 0, 0); >How We ll Take Care of You:</span></strong></span></p>\n<p class= p1 >Our job titles may span more than one career or degree level. The base pay range shown below is monthly, is subject to change and may be modified in the future. This role may also be eligible for benefits.</p></div><div class= title >Brazil Monthly Pay Range</div><div class= pay-range ><span>R$3.000</span><span class= divider > </span><span>R$3.000 BRL</span></div></div></div>','\n',char(10)),63,'entry-level + CS/tech + internship','new','566db02912842bab804e8626130a41ac665e37bb71b441acd896ae684ae4d458','2026-06-02T06:56:13Z','global');
INSERT INTO "opportunities" ("id","type","title","organization","source","url","location","deadline","description","fit_score","fit_reason","status","dedup_hash","discovered_at","region") VALUES(29,'internship','Field Sales Intern, EMEA Services','Airbnb','greenhouse','https://careers.airbnb.com/positions/7904319?gh_jid=7904319','Barcelona, Spain, Milan, Italy, Paris, France',NULL,replace('<div class= content-intro ><p><span style= font-family: helvetica, arial, sans-serif; font-size: 12pt; >Airbnb was born in 2007 when two hosts welcomed three guests to their San Francisco home, and has since grown to over 5 million hosts who have welcomed over 2 billion guest arrivals in almost every country across the globe. Every day, hosts offer unique stays and experiences that make it possible for guests to connect with communities in a more authentic way.</span></p></div><p> </p>\n<p><strong>The community you will join:</strong></p>\n<p>Airbnb is seeking Field Sales Interns to join the EMEA Services team for a 6-month internship.</p>\n<p>Just like Airbnb disrupted hospitality, Airbnb Services is redefining the guest experience by bringing premium in-home services directly to Airbnb stays. Airbnb Services offers 10 categories (chefs, photography, massage, personal training, nails, etc.) across 280 cities, with new offerings and locations dropping regularly in the Airbnb app.</p>\n<p>We’re seeking a dynamic and people-oriented person to be the frontline voice of Airbnb Services in EMEA. This role focuses on the acquisition of key hosts in Paris, Milan, or Barcelona (depending on location of role).</p>\n<p> </p>\n<p><strong>The difference you will make:</strong></p>\n<p>As a field sales, you’ll work on projects that cover the following:</p>\n<ul>\n<li><strong>Lead Generation:</strong> Identify potential leads sourcing through online research, community engagement and local networking.</li>\n<li><strong>Cold outreach:</strong> connect with potential hosts through mails, cold callings as well as in-person visits.</li>\n<li><strong>Sales Pitches: </strong>Deliver persuasive in-person conversations to showcase Airbnb Services and its offerings, effectively converting interest into host submissions.</li>\n<li><strong>Onboarding:</strong> Partner with cross-functional teams to facilitate the initial onboarding of new hosts, ensuring they are well-informed and equipped for success.</li>\n</ul>\n<p> </p>\n<p><strong>The intern experience:</strong></p>\n<p>As an intern, you’ll be integrated into a team where you’ll contribute to challenging projects. Your manager, team, and our incredible employee community will strive to be superhosts to you during the summer. We provide the support, mentorship, fun, and real world experience needed to accelerate your learning and make a real impact on our product, as Airbnb revolutionizes connection, belonging, and travel. You can expect to:</p>\n<ul>\n<li>Collaborate with multiple team members to achieve project milestones</li>\n<li>Communicate with stakeholders across different teams to provide project updates</li>\n<li>Seek and provide feedback throughout the internship</li>\n<li>Actively participate in and contribute to the Airbnb Services Supply team and broader Airbnb community</li>\n</ul>\n<p> </p>\n<p><strong>Your expertise:</strong></p>\n<ul>\n<li>Current master’s student (or recently graduated within the last year) in a top engineering or business school, with at least 3 years of studies completed.</li>\n<li>One first commercial experience in sales, partnerships, account management, or community engagement.</li>\n<li>Exceptional interpersonal skills; comfortable with cold calling and initiating conversations in various formats.</li>\n<li>A curious and scrappy mindset with an eagerness to proactively identify new tactics   approaches to source, engage and close successful leads.</li>\n<li>Highly organized, with the ability to manage multiple conversations and leads across various platforms.</li>\n<li>Clear and positive communicator, both verbally and in writing, with an authentic voice.</li>\n<li>Passionate about Airbnb’s mission to create belonging and economic opportunity for hosts.</li>\n<li>Familiarity with social platforms (Facebook Groups, Reddit, Nextdoor) for community engagement and lead generation.</li>\n<li>Experience with or understanding of small business owners, hosts, or side hustlers is a plus.</li>\n<li>Based in Barcelona, Milan or Paris and deep local knowledge of the market and its service offerings.</li>\n<li>Native speaker of French, Italian, and/or Spanish and fluent in English (written and spoken) </li>\n</ul>\n<p> </p>\n<p><strong>Your location:</strong></p>\n<p>This position is hybrid (half remote half onsite) and you must be living in Barcelona, Milan or Paris and have work authorization for one of those countries to be eligible.</p>\n<p> </p>\n<p><strong>Our commitment to inclusion and belonging:</strong></p>\n<p>Airbnb is committed to working with the broadest talent pool possible. We believe diverse ideas foster innovation and engagement, and allow us to attract creatively-led people, and to develop the best products, services and solutions. All qualified individuals are encouraged to apply.</p>\n<p>We strive to also provide a disability inclusive application and interview process. If you are a candidate with a disability and require reasonable accommodation in order to submit an application, please contact us at: reasonableaccommodations@airbnb.com. Please include your full name, the role you’re applying for and the accommodation necessary to assist you with the recruiting process. </p>\n<p>We ask that you only reach out to us if you are a candidate whose disability prevents you from being able to complete our online application.</p>\n<p><br><br></p>\n<p><strong>Please submit all application materials in English.</strong></p><div class= content-pay-transparency ><div class= pay-input ><div class= description ><p><span style= font-size: 16px; ><strong><span style= font-family: arial, helvetica, sans-serif; color: rgb(0, 0, 0); >How We ll Take Care of You:</span></strong></span></p>\n<p>The base pay range shown below is annualized, is subject to change and may be modified in the future.  This role may also be eligible for benefits and Employee Travel Credits. </p></div><div class= title >France Annual Pay Range</div><div class= pay-range ><span>€25.000</span><span class= divider > </span><span>€25.000 EUR</span></div></div><div class= pay-input ><div class= description ><p><span style= font-size: 16px; ><strong><span style= font-family: arial, helvetica, sans-serif; color: rgb(0, 0, 0); >How We ll Take Care of You:</span></strong></span></p>\n<p><span style= font-size: 16px; >The base pay range shown below is annualized, is subject to change and may be modified in the future. This role may also be eligible for benefits and Employee Travel Credits.</span></p></div><div class= title >Italy Annual Pay Range</div><div class= pay-range ><span>€20.000</span><span class= divider > </span><span>€20.000 EUR</span></div></div><div class= pay-input ><div class= description ><p><span style= font-size: 16px; ><strong><span style= font-family: arial, helvetica, sans-serif; color: rgb(0, 0, 0); >How We ll Take Care of You:</span></strong></span></p>\n<p><span style= font-size: 16px; >The base pay range shown below is annualized, is subject to change and may be modified in the future. This role may also be eligible for benefits and Employee Travel Credits.</span></p></div><div class= title >Spain Annual Pay Range</div><div class= pay-range ><span>€20.000</span><span class= divider > </span><span>€20.000 EUR</span></div></div></div>','\n',char(10)),63,'entry-level + CS/tech + internship','new','4f8f166d59c310e66cae629fb45da8c1c986ca3152035e0a99f14227e724b005','2026-06-02T06:56:13Z','global');
INSERT INTO "opportunities" ("id","type","title","organization","source","url","location","deadline","description","fit_score","fit_reason","status","dedup_hash","discovered_at","region") VALUES(30,'internship','iOS Software Engineer, Airbnb - New Grad','Airbnb','greenhouse','https://careers.airbnb.com/positions/7859317?gh_jid=7859317','San Francisco, CA, Seattle, WA',NULL,replace('<div class= content-intro ><p><span style= font-family: helvetica, arial, sans-serif; font-size: 12pt; >Airbnb was born in 2007 when two hosts welcomed three guests to their San Francisco home, and has since grown to over 5 million hosts who have welcomed over 2 billion guest arrivals in almost every country across the globe. Every day, hosts offer unique stays and experiences that make it possible for guests to connect with communities in a more authentic way.</span></p></div><p> </p>\n<p><strong>The Community You Will Join:</strong></p>\n<p>The Quality Reputation team is dedicated to building exceptional customer-facing products that enhance trip quality and user reputation. We build systems that define and improve quality on Airbnb: collecting quality signals that elevate the best supply while protecting users through proactive intervention and enforcement. Our mission is to build delightful user products and intelligent capabilities that raise the supply quality on the Airbnb platform. The team is highly collaborative with its partners in design, product, data science, legal, and marketing to deliver features and experiences used by millions of people.</p>\n<p> </p>\n<p><strong>The Difference You Will Make:</strong></p>\n<p>As a Software Engineer (New Grad) at Airbnb, you’ll play a vital role in building, supporting, and refining the products and systems that make Airbnb’s mission possible. Your work will directly contribute to high-quality, reliable experiences for our global community—whether you’re fixing bugs, launching well-defined features, or enhancing existing components. You ll also have the opportunity to contribute to AI-powered features, applying foundational knowledge of machine learning concepts and modern AI tools to build smarter, more personalized experiences for our hosts and guests. By clearly communicating challenges and collaborating with teammates across functions, you’ll help drive projects forward with transparency and trust.</p>\n<p>You’ll foster a sense of belonging by actively seeking feedback, sharing your own learnings, and supporting the onboarding of new team members. You’ll help uphold Airbnb’s commitment to excellence by following best practices, delivering tasks autonomously, and continually improving your technical skills. Your curiosity, empathy, and commitment to candid communication will empower you to make a meaningful impact—on projects, teammates, and Airbnb’s inclusive culture.</p>\n<p> </p>\n<p><strong>A Typical Day: </strong></p>\n<ul>\n<li>Attend team syncs to discuss priorities, share progress, and surface any blockers with transparency.</li>\n<li>Dive into coding — fixing bugs, developing iOS features, or refining UI components —while applying best practices for code quality, error handling, and testability. Leverage AI-assisted development tools (e.g., Claude Code or similar) to accelerate your workflow and improve code quality.</li>\n<li>Participate in design or code reviews, ask clarifying questions, and apply feedback to improve your work. Work closely with cross-functional partners like product managers and designers to ensure your tasks align clearly with broader goals.</li>\n<li>Dedicate time to expanding your technical knowledge through documentation, mentorship, or internal knowledge-sharing sessions. This includes staying current on iOS platform developments or AI/ML topics relevant to your team s domain. Seek guidance from managers or tech leads when tackling unfamiliar problems.</li>\n<li>Contribute to team activities, such as onboarding new hires (e.g., being an onboarding buddy), sharing observations from the hiring process, or joining in cultural events focused on diversity, inclusion, and innovation.</li>\n<li>Share updates on your progress and next steps, highlighting challenges or learnings. </li>\n</ul>\n<p> </p>\n<p><strong>Your Expertise:</strong></p>\n<p>This role is designed for recent graduates (Bachelor s or Master s) with less than 1 year of full-time professional experience who are ready to grow fast and make an impact.</p>\n<ul>\n<li>Strong foundation in Computer Science fundamentals — data structures, algorithms, design patterns, and systems thinking</li>\n<li>Proficiency in Swift, with exposure to SwiftUI or UIKit for building iOS applications</li>\n<li>Foundational understanding of iOS development concepts — including networking, caching, client storage, accessibility, and asynchronous programming</li>\n<li>Familiarity with REST APIs; exposure to GraphQL is a plus</li>\n<li>Bonus points for leadership experience, community involvement, or teaching/mentoring — we love engineers who invest in others</li>\n</ul>\n<p> </p>\n<p><strong>Your Location:</strong></p>\n<p>Preference for candidates based in San Francisco, California or Seattle, Washington with the ability to commute to the office three days per week. Additional in-person attendance for team meetings or offsites may be required as needed. Domestic Relocation support will be provided for candidates open to relocating.</p>\n<p> </p>\n<p><strong>Our Commitment To Inclusion   Belonging:</strong></p>\n<p>Airbnb is committed to working with the broadest talent pool possible. We believe diverse ideas foster innovation and engagement, and allow us to attract creatively-led people, and to develop the best products, services and solutions. All qualified individuals are encouraged to apply.</p>\n<p>We strive to also provide a disability inclusive application and interview process. If you are a candidate with a disability and require reasonable accommodation in order to submit an application, please contact us at: <a href= mailto:reasonableaccommodations@airbnb.com >reasonableaccommodations@airbnb.com</a>. Please include your full name, the role you’re applying for and the accommodation necessary to assist you with the recruiting process. </p>\n<p>We ask that you only reach out to us if you are a candidate whose disability prevents you from being able to complete our online application. </p>\n<p> </p><div class= content-pay-transparency ><div class= pay-input ><div class= description ><p><span style= font-size: 16px; ><strong><span style= font-family: arial, helvetica, sans-serif; color: rgb(0, 0, 0); >How We ll Take Care of You:</span></strong></span></p>\n<p class= p1 ><span style= font-size: 16px; >Our job titles may span more than one career level. The actual base pay is dependent upon many factors, such as: training, transferable skills, work experience, business needs and market demands. The base pay range is subject to change and may be modified in the future. This role may also be eligible for bonus, equity, benefits, and Employee Travel Credits.  </span></p></div><div class= title >Pay Range</div><div class= pay-range ><span>$128,000</span><span class= divider > </span><span>$142,000 USD</span></div></div></div>','\n',char(10)),80,'entry-level + CS/tech + internship','new','d7c1a45f28273a3292ae852e8e89d8a62f2b6d60b7caa30a49fe63c803d77167','2026-06-02T06:56:13Z','global');
INSERT INTO "opportunities" ("id","type","title","organization","source","url","location","deadline","description","fit_score","fit_reason","status","dedup_hash","discovered_at","region") VALUES(31,'internship','Legal Intern, Brazil','Airbnb','greenhouse','https://careers.airbnb.com/positions/7886515?gh_jid=7886515','São Paulo, Brazil',NULL,replace('<div class= content-intro ><p><span style= font-family: helvetica, arial, sans-serif; font-size: 12pt; >Airbnb was born in 2007 when two hosts welcomed three guests to their San Francisco home, and has since grown to over 5 million hosts who have welcomed over 2 billion guest arrivals in almost every country across the globe. Every day, hosts offer unique stays and experiences that make it possible for guests to connect with communities in a more authentic way.</span></p></div><p><strong>The community you will join:</strong></p>\n<p>Airbnb is seeking a Legal Intern to join the Brazil legal consulting and Litigation teams for a 24-month internship.</p>\n<p>Airbnb’s legal team embodies the company’s innovative and entrepreneurial spirit. At the frontier of the sharing economy, Airbnb is breaking new ground in matters of policy and law around the world. Where some see obstacles, we see opportunities to find creative and practical solutions. We’re an adventurous, fast-moving group. This internship is right for you if you are a law student (bachelor) with a proactive attitude, strong organization skills, willingness to learn, and embrace adventures in a fast paced environment. </p>\n<p>Airbnb is committed to supporting students from underrepresented backgrounds in law and tech. We are looking for candidates who identify as black and highly encourage them to apply.</p>\n<p> </p>\n<p><strong>The difference you will make:</strong></p>\n<p>As an intern, you’ll be integrated into a team where you’ll contribute to challenging projects. Your manager, team, and our incredible employee community will strive to be superhosts to you. We provide the support, mentorship, fun, and real world experience needed to accelerate your learning and make a real impact on our product, as Airbnb revolutionizes connection, belonging, and travel.</p>\n<p>Your assigned projects will depend on the department’s needs and your interests. You will have the opportunity to work closely with the Litigation team of Airbnb Brazil to support a variety of litigation functions.</p>\n<p> </p>\n<p><strong>A typical day:</strong></p>\n<p>The intern will support the Brazil Litigation team in:</p>\n<ul>\n<li>Managing summonings from judicial and administrative cases and extrajudicial notices;</li>\n<li>Monitoring judicial and administrative cases, gathering data to support Airbnb s defenses and updating Airbnb s internal systems with information about judicial and administrative cases;</li>\n<li>Managing outside counsel work and consumer litigation cases;</li>\n<li>Drafting reports and responses to judicial and administrative requests</li>\n<li>Participating on the Litigation Team s projects, besides collaborating on daily basis workflows.</li>\n</ul>\n<p> </p>\n<p><strong>Your expertise:</strong></p>\n<ul>\n<li>Current second or third year law school student</li>\n<li>Advanced proficiency in the English language</li>\n<li>Interpersonal skills with an interest in building relationships and collaborating across the company</li>\n<li>Adaptable and able to adjust plans and manage changes effectively</li>\n<li>Able to prioritize tasks, meet deadlines, and handle multiple projects simultaneously</li>\n<li>Strong interest in learning about in-house legal practice</li>\n<li>Previous experience in the litigation practice is a plus but not required</li>\n</ul>\n<p> </p>\n<p><strong>Your location:</strong></p>\n<p>Due to the nature of this position, the successful applicant will need to be based in São Paulo for in-person meetings and collaboration. Additionally, you must have work authorization for Brazil to be eligible. </p>\n<p> </p>\n<p><strong>Our commitment to inclusion   belonging:</strong></p>\n<p>Airbnb is committed to working with the best and brightest people from the broadest talent pool possible. We believe a diversity of ideas fosters innovation and engagement, and allows us to attract the best people, and to develop the best products, services and solutions. All qualified individuals are encouraged to apply. If you need assistance, or a reasonable accommodation during the application and recruiting process, please contact us at: <a href= mailto:reasonableaccommodations@airbnb.com >reasonableaccommodations@airbnb.com</a>.</p>\n<p> </p>\n<p><strong>Please submit all application materials in English.</strong></p><div class= content-pay-transparency ><div class= pay-input ><div class= description ><p><span style= font-size: 16px; ><strong><span style= font-family: arial, helvetica, sans-serif; color: rgb(0, 0, 0); >How We ll Take Care of You:</span></strong></span></p>\n<p class= p1 >Our job titles may span more than one career or degree level. The base pay range shown below is monthly, is subject to change and may be modified in the future. This role may also be eligible for benefits.</p></div><div class= title >Brazil Monthly Pay Range</div><div class= pay-range ><span>R$3.000</span><span class= divider > </span><span>R$3.000 BRL</span></div></div></div>','\n',char(10)),72,'entry-level + CS/tech + internship','new','cbaf57e2a731747674fec986dd6e0170f5763e733ad67e231718c162f60dd946','2026-06-02T06:56:13Z','global');
INSERT INTO "opportunities" ("id","type","title","organization","source","url","location","deadline","description","fit_score","fit_reason","status","dedup_hash","discovered_at","region") VALUES(32,'internship','Director of Internal Audit','Robinhood','greenhouse','https://boards.greenhouse.io/robinhood/jobs/7490045?t=gh_src=&gh_jid=7490045','London, UK',NULL,replace('<div class= content-intro ><h2>Join us in building the future of finance.</h2>\n<p>Our mission is to democratize finance for all. <a href= https://www.cerulli.com/press-releases/cerulli-anticipates-124-trillion-in-wealth-will-transfer-through-2048  target= _blank >An estimated $124 trillion of assets</a> will be inherited by younger generations in the next two decades. The largest transfer of wealth in human history. If you’re ready to be at the epicenter of this historic cultural and financial shift, keep reading.</p></div><h2><strong>About the team + role</strong></h2>\n<p>We are building an elite team, applying frontier technologies to the world’s biggest financial problems.<strong> </strong>We’re looking for bold thinkers. Sharp problem-solvers. Builders who are wired to make an impact. Robinhood isn’t a place for complacency, it’s where ambitious people do the best work of their careers. We’re a high-performing, fast-moving team with ethics at the center of everything we do. Expectations are high, and so are the rewards.</p>\n<p>The Internal Audit function provides independent, objective, reliable, valued and timely assurance regarding the effectiveness of governance, risk management, and internal controls that mitigate current and emerging risks and help strengthen the internal controls ecosystem.</p>\n<p>The Internal Audit team at Robinhood provides governance and oversight for the Company and across its regulated entities. The function also facilitates communication of risk management information between the regulated entities’ RHM leadership, and the Company’s Board of Directors and its Committees, strengthening the Company’s risk management, internal controls, and governance.  </p>\n<p>As Director of Internal Audit, you will be charged with overseeing the execution of audits for Robinhood’s International Entities, across Brokerage and Crypto products and supporting integrated audits across the various lines of businesses.  </p>\n<p>This position requires a leader with expert understanding of risks in a regulated Fintech setting. The successful candidate is a proven leader, collaborative, analytical, technical expert that can lead audits across multiple disciplines.</p>\n<p><strong>This role is based in our </strong><strong>London, UK or Luxembourg</strong><strong> office, with in-person attendance expected 5 </strong><strong>days per week. </strong></p>\n<p>At Robinhood, we believe in the power of in-person work to accelerate progress, spark innovation, and strengthen community. Our office experience is intentional, energizing, and designed to fully support high-performing teams.</p>\n<h2><strong>What you’ll do</strong></h2>\n<ul>\n<li>Assist Audit leadership with risk assessments, development of the Internal Audit plan and the overall strategic direction of the parent company Internal Audit program</li>\n<li>Be accountable for the achievement of Internal Audit objectives as they align to the internal audit strategy and company OKRs</li>\n<li>Be responsible for the execution of end-to-end audit procedures in the audit lifecycle including, audit planning, execution, reporting and remediation validation</li>\n<li>Conclude on audit results and present ratings and recommendations to senior management, executive team members, Management Boards and the parent company Audit Committee as needed.</li>\n<li>Oversee the performance of the internal audit team members and third-parties that support the execution of audits, regulatory or board reporting.</li>\n<li>Lead the discussion on audit topics to various levels of management within Brokerage, Crypto, Security   Engineering teams. Influence management to act on recommendations to strengthen the control environment and make process improvements.</li>\n<li>Establish and manage relationships with senior leaders and risk partners. Share perspectives including industry best practices, audit standards, regulatory requirements and global impact with key stakeholders.</li>\n<li>Support the creation of reports and presentations for the department, Robinhood entities, Audit Committee, regulators and external auditors.</li>\n<li>Partner on continuous development and enhancement of the Audit practice to align with the overall objective and goals of the parent company Audit function (including development of frameworks, metrics, procedures, partnerships, communications and training programs). </li>\n<li>Participate in special projects and perform other duties as assigned.</li>\n</ul>\n<h2><strong>What you bring</strong></h2>\n<ul>\n<li>Bachelor’s degree in a relevant field of study (e.g. Business, Risk Management, Computer Science, Information Systems, Data Science or Computer Engineering)</li>\n<li>10+ years of auditing experience, including Operations and IT auditing, risk management, Compliance, Information Security, or software development</li>\n<li>Expertise in Brokerage, Crypto financial products and regulatory compliance</li>\n<li>Ability to partner with business, engineering, data and product teams to strengthen controls environment using automated techniques</li>\n<li>Strong demonstrated experience in managing executive reporting; excellent interpersonal, leadership, organizational and communication (verbal and written) skills</li>\n<li>Experience in end-to-end project management and cross-functional collaboration</li>\n<li>Experience independently operates in a fast-paced, dynamic environment while managing multiple projects/initiatives</li>\n<li>Passion for Robinhood’s products and our mission to democratize access to global financial systems</li>\n</ul>\n<h2><strong>What we offer</strong></h2>\n<ul>\n<li>Challenging, high-impact work to grow your career</li>\n<li>Top tier benefits to fuel your work, including supplemental health insurance, ancillary insurance, and mental health support programs</li>\n<li>Lifestyle wallet - a highly flexible employer-paid benefits spending account expenses beyond traditional benefits such as wellness, childcare, learning, and more.</li>\n<li>Time off to recharge including company holidays, paid time off, sick time, paid volunteer time off, parental leave, and more!</li>\n<li>Exceptional office experience with catered meals, events, and comfortable workspaces. </li>\n<li>Monthly commuter stipend to help offset in-office commuting costs</li>\n</ul>\n<h2><strong>Crypto   Brokerage Experience</strong></h2>\n<ul>\n<li>Experience with licensing and regulatory compliance requirements in Europe and Asia (MiCA, CASP, VASP, Mifid II, MAS, DORA, GDPR etc.)</li>\n<li>Hands-on experience performing crypto product related audits (e.g. spot, derivatives, tokenization) used by retail and institutional customers </li>\n<li>Hands-on experience performing brokerage audits (e.g. consumer duty principle, trading on margin, trade reporting)</li>\n<li>Experience with regulators such as CSSF, ATVP, FCA</li>\n</ul><div class= content-conclusion ><p>Click <a href= https://careers.robinhood.com/benefits  target= _blank >here</a> to learn more about our Total Rewards, which vary by region and entity.</p>\n<p>If our mission energizes you and you’re ready to build the future of finance, we look forward to seeing your application.</p>\n<p>Robinhood provides equal opportunity for all applicants, offers reasonable accommodations upon request, and complies with applicable equal employment and privacy laws. Inclusion is built into how we hire and work—welcoming different backgrounds, perspectives, and experiences so everyone can do their best. Please review the <a href= https://careers.robinhood.com/applicantprivacypolicy  target= _blank >Privacy Policy</a> for your country of application.</p></div>','\n',char(10)),10,'senior (penalized) + CS/tech + internship','new','f021f32ebed5291c6ef859c62469b94f09647bf8d3735db819802427293230b8','2026-06-02T06:56:15Z','global');
