INSERT INTO "opportunities" ("id","type","title","organization","source","url","location","deadline","description","fit_score","fit_reason","status","dedup_hash","discovered_at","region") VALUES(112,'internship','Senior Frontend Engineer - Internal Tools','Jobgether','lever','https://jobs.lever.co/jobgether/4b3988f2-bf6e-4980-b9f5-eb65dde38ce9','Germany',NULL,replace('This position is posted by Jobgether on behalf of a partner company. We are currently looking for a Senior Frontend Engineer - Internal Tools in Germany.\n\nThis role offers the opportunity to build and enhance the internal platforms and applications that support complex financial operations at scale. As a senior member of the engineering team, you will create intuitive, high-performance user experiences that empower internal stakeholders and improve operational efficiency. Working across both frontend and backend systems, you will contribute to the design, architecture, and delivery of critical tools used in a fast-moving technology environment. The position combines hands-on development with technical leadership, giving you the chance to mentor engineers, influence engineering standards, and shape product direction. You will collaborate closely with cross-functional teams to deliver polished, accessible, and scalable solutions that directly impact millions of end users. This is an ideal opportunity for a frontend specialist who enjoys ownership, innovation, and solving complex technical challenges in a distributed, remote-first setting.\n\nAccountabilities:\n\nDesign, develop, and maintain modern web and mobile applications that support internal operational workflows and business-critical functions.\nBuild responsive, performant, and user-friendly interfaces using modern frontend technologies and best practices.\nCollaborate with product managers, designers, and engineers to transform requirements and designs into production-ready solutions.\nOwn the delivery of high-visibility projects from architecture and implementation through deployment and ongoing optimization.\nContribute to both frontend and backend development where required, ensuring seamless integration across systems.\nEstablish and promote frontend engineering standards, coding best practices, accessibility principles, and performance optimization techniques.\nMentor team members, conduct code reviews, and provide technical guidance to support engineering excellence.\nParticipate in architectural discussions and influence technical strategy for internal products and platforms.\nEnsure applications maintain high standards of reliability, usability, scalability, and maintainability.\n\nRequirements:\n\n5+ years of professional frontend engineering experience with strong expertise in TypeScript and React.\n2+ years of experience working with modern systems programming languages such as Go, Rust, or C++.\nStrong understanding of frontend architecture, component design, state management, and performance optimization.\nProficiency in HTML, CSS, and modern styling frameworks such as Tailwind CSS.\nExperience integrating REST APIs, WebSocket services, and distributed backend systems.\nKnowledge of relational databases, SQL, and data-driven application development.\nProven ability to translate product requirements and design mockups into polished, production-ready user experiences.\nStrong communication, collaboration, and stakeholder management skills within cross-functional teams.\nDemonstrated experience influencing engineering standards and frontend best practices.\nAttention to detail, user experience quality, accessibility, and visual design consistency.\nExperience with cloud platforms, financial technology products, startup environments, or remote-first teams is considered an advantage.\n\nBenefits:\n\nCompetitive salary package with equity participation opportunities.\nComprehensive health and wellness benefits.\nFully remote work environment with flexibility across Europe and the United Kingdom.\nOne-time home office setup allowance to create a productive remote workspace.\nMonthly stipend to support professional and remote working expenses.\nOpportunity to work on products serving millions of users and processing significant transaction volumes.\nCareer growth opportunities within a rapidly scaling global technology organization.\nCollaborative and diverse international team culture.\nExposure to modern technologies, large-scale distributed systems, and financial infrastructure.\nStrong focus on learning, mentorship, innovation, and professional development.\n\nHow Jobgether works:\nWe use an AI-powered matching process to ensure your application is reviewed quickly, objectively, and fairly against the role''s core requirements. Our system identifies the top-fitting candidates, and this shortlist is then shared directly with the hiring company. The final decision and next steps (interviews, assessments) are managed by their internal team.\nWe appreciate your interest and wish you the best!\n Why Apply Through Jobgether? \n \nData Privacy Notice: By submitting your application, you acknowledge that Jobgether will process your personal data to evaluate your candidacy and share relevant information with the hiring employer. This processing is based on legitimate interest and pre-contractual measures under applicable data protection laws (including GDPR). You may exercise your rights (access, rectification, erasure, objection) at any time.\n \n \n#LI-CL1','\n',char(10)),10,'senior (penalized) + CS/tech + internship','new','5d9d832cdd10001f0789b7d531760dac708185ebc8977ea71dd6123fb5d03059','2026-06-02T08:12:26Z','global');
