INSERT INTO "opportunities" ("id","type","title","organization","source","url","location","deadline","description","fit_score","fit_reason","status","dedup_hash","discovered_at","region") VALUES(119,'internship','Senior International Sales Manager','Jobgether','lever','https://jobs.lever.co/jobgether/2808c14c-134c-45ca-949a-48b919a69710','Spain',NULL,replace('This position is posted by Jobgether on behalf of a partner company. We are currently looking for a Senior International Sales Manager in Spain.\n\nThis is a high-impact global commercial role focused on driving international growth across Europe, Asia-Pacific, and Latin America within the medical device sector. You will be responsible for expanding market presence, strengthening distributor networks, and accelerating revenue performance across multiple regions. The role combines strategic sales leadership with hands-on execution, requiring close collaboration with clinical stakeholders, distributors, and healthcare professionals. You will play a key role in shaping and executing regional sales strategies, identifying new business opportunities, and supporting surgical adoption of innovative bone repair technologies. Operating in a fast-paced, regulated healthcare environment, you will manage complex international relationships while ensuring compliance and commercial excellence. This position is ideal for a results-driven sales leader who thrives in global, cross-functional environments and is motivated by meaningful impact in healthcare innovation.\n\nAccountabilities:\n\nManage sales objectives across assigned international regions, ensuring revenue and unit growth through strong distributor and partner relationships.\nDevelop, implement, and execute annual regional sales strategies aligned with global business objectives.\nForecast sales performance, track progress against targets, and adjust plans to ensure consistent achievement of commercial goals.\nIdentify, qualify, and develop new business opportunities through networking, referrals, marketing initiatives, and direct outreach.\nBuild and maintain strong relationships with key surgeons, distributors, and commercial partners to drive product adoption and growth.\nProvide technical and clinical support by addressing questions related to surgical applications and product usage in orthopedics and spine procedures.\nSupport case coverage, in-servicing, and training activities for distributors and field representatives.\nLead and mentor sales agents, ensuring effective onboarding, training, and ongoing performance improvement.\n\nRequirements:\n\n5–10+ years of experience in medical device sales, preferably within spine, orthopedics, or related healthcare sectors.\nProven track record of achieving or exceeding international sales targets and managing distributor networks.\nStrong understanding of global healthcare markets, regulatory environments, and commercial dynamics.\nExcellent negotiation, communication, and presentation skills with the ability to influence senior stakeholders.\nExperience working across multiple time zones and managing international business relationships.\nStrong organizational, multitasking, and time management abilities in complex environments.\nProficiency in Microsoft Office tools (Outlook, Word, Excel, PowerPoint).\nAbility to handle confidential information with discretion and professionalism.\nWillingness to travel internationally up to 30% of the time.\nBachelor’s degree in a science-related field is preferred.\n\nBenefits:\n\nCompetitive base salary with performance-based variable compensation.\nComprehensive benefits package including medical, dental, life insurance, and long-term disability coverage.\n401(k) retirement savings plan with company matching (where applicable).\nPaid time off and flexible work arrangements within a remote structure.\nOpportunity to work in a global, mission-driven healthcare organization focused on improving patient outcomes.\nExposure to international markets across Europe, Asia-Pacific, and Latin America.\nCareer development opportunities in a high-growth, commercial-stage medical device company.\n\nHow Jobgether works:\nWe use an AI-powered matching process to ensure your application is reviewed quickly, objectively, and fairly against the role''s core requirements. Our system identifies the top-fitting candidates, and this shortlist is then shared directly with the hiring company. The final decision and next steps (interviews, assessments) are managed by their internal team.\nWe appreciate your interest and wish you the best!\n Why Apply Through Jobgether? \n \nData Privacy Notice: By submitting your application, you acknowledge that Jobgether will process your personal data to evaluate your candidacy and share relevant information with the hiring employer. This processing is based on legitimate interest and pre-contractual measures under applicable data protection laws (including GDPR). You may exercise your rights (access, rectification, erasure, objection) at any time.\n \n \n#LI-CL1','\n',char(10)),0,'senior (penalized) + CS/tech + internship','new','01365ffc1abf09ef284b1577dc1ec6fbd606968cf077ca7f1960f35b8a5dd4de','2026-06-02T08:12:26Z','global');
