INSERT INTO "opportunities" ("id","type","title","organization","source","url","location","deadline","description","fit_score","fit_reason","status","dedup_hash","discovered_at","region") VALUES(126,'internship','Senior Manager, Internal Communications','Jobgether','lever','https://jobs.lever.co/jobgether/1f6f8775-21dd-4e7f-983a-77f128af11c9','US',NULL,replace('This position is posted by Jobgether on behalf of a partner company. We are currently looking for a Senior Manager, Internal Communications in United States.\n\nThis is a unique opportunity for a strategic communicator to shape and elevate the employee experience within a fast-growing, mission-driven organization. In this high-impact remote role, you will lead internal communications initiatives that foster alignment, transparency, and engagement across teams and leadership. You’ll collaborate closely with executives and cross-functional stakeholders to craft compelling narratives, manage high-visibility announcements, and establish scalable communication systems. The position combines strategic ownership with hands-on execution, making it ideal for someone who thrives in dynamic environments and enjoys building processes from the ground up. With a strong emphasis on culture, purpose, and innovation, this role offers the chance to directly influence how employees connect with the company’s mission and growth journey.\n\nAccountabilities:\n\nDevelop and execute a comprehensive internal communications strategy that supports organizational alignment and employee engagement across multiple channels and teams.\nPartner with senior leadership to craft impactful executive communications, ensuring messaging is clear, authentic, and aligned with company priorities and culture.\nLead communications planning and execution for major company announcements, organizational updates, and other high-visibility initiatives.\nCreate scalable communication frameworks, workflows, and tools, including AI-enabled solutions, to improve consistency and operational efficiency.\nCollaborate closely with People, Corporate Communications, and other departments to maintain cohesive messaging and communication cadence throughout the organization.\nEstablish and refine the company’s internal voice and storytelling approach to ensure employees remain informed, inspired, and connected.\nDrive engagement by implementing effective communication practices that support transparency, trust, and collaboration across distributed teams.\n\nRequirements:\n\n8+ years of experience in internal communications, employee communications, or corporate communications within fast-paced or high-growth environments.\nProven expertise in executive communications, including advising senior leaders and developing messaging for complex or high-stakes situations.\nExceptional writing, editing, and storytelling abilities with a strong understanding of voice, tone, and audience engagement.\nDemonstrated ability to independently lead both strategic planning and hands-on execution of communication initiatives.\nStrong collaboration and stakeholder management skills, with the ability to influence cross-functional teams and navigate evolving priorities.\nExperience building communication systems, processes, and scalable frameworks from the ground up.\nAbility to thrive in remote and dynamic environments while managing multiple priorities effectively.\nExperience within mission-driven organizations or companies focused on social impact is considered a plus.\n\nBenefits:\n\nCompetitive salary range of $145,000 – $218,000 USD plus equity opportunities.\nFully remote work flexibility across the United States.\nComprehensive healthcare coverage and wellness support programs.\nGenerous parental leave and flexible paid time off policies.\nFinancial assistance for remote or hybrid work arrangements and family planning support.\nLearning, development, and employee recognition programs designed to support career growth.\nInclusive and collaborative work culture with strong Diversity, Equity, and Inclusion initiatives.\nVolunteer and community engagement opportunities that align with a meaningful social mission.\n\nHow Jobgether works:\nWe use an AI-powered matching process to ensure your application is reviewed quickly, objectively, and fairly against the role''s core requirements. Our system identifies the top-fitting candidates, and this shortlist is then shared directly with the hiring company. The final decision and next steps (interviews, assessments) are managed by their internal team.\nWe appreciate your interest and wish you the best!\n Why Apply Through Jobgether? \n \nData Privacy Notice: By submitting your application, you acknowledge that Jobgether will process your personal data to evaluate your candidacy and share relevant information with the hiring employer. This processing is based on legitimate interest and pre-contractual measures under applicable data protection laws (including GDPR). You may exercise your rights (access, rectification, erasure, objection) at any time.\n \n \n#LI-CL1','\n',char(10)),0,'senior (penalized) + CS/tech + internship','new','19434f457273fd6ed0165d60690e9ce85164ff8b7e34bbb17f654dc92c757c8d','2026-06-02T08:12:26Z','global');
INSERT INTO "opportunities" ("id","type","title","organization","source","url","location","deadline","description","fit_score","fit_reason","status","dedup_hash","discovered_at","region") VALUES(127,'internship','Senior Manager, Internal Communications','Jobgether','lever','https://jobs.lever.co/jobgether/bb79521b-e2e3-43b2-a30e-d9e5f6bb4703','US',NULL,replace('This position is posted by Jobgether on behalf of a partner company. We are currently looking for a Senior Manager, Internal Communications in United States.\n\nThis is a high-impact, company-wide communications leadership role responsible for shaping how employees are informed, aligned, and inspired across a fast-moving, mission-driven organization. You will define and execute the internal communications strategy, ensuring clarity and consistency across leadership messaging, organizational updates, and cultural narratives. Acting as both strategist and hands-on communicator, you will partner closely with executive leaders and People teams to elevate internal voice and storytelling. The role requires strong judgment, the ability to simplify complex information, and comfort operating in high-visibility moments. You will also build scalable systems and processes that modernize how information flows across the organization. This is an opportunity to directly influence employee experience and engagement at scale while helping strengthen organizational alignment during periods of growth and change.\n\nAccountabilities\n\nDefine and lead the internal communications strategy, establishing clear frameworks for employee communication across channels, audiences, and key organizational moments.\nDevelop and maintain a consistent internal voice and narrative, ensuring alignment across executive leadership and functional teams.\nLead executive communications, partnering with senior leaders to craft clear, compelling messaging for company-wide updates and strategic priorities.\nOwn communication planning for high-visibility events such as organizational changes, launches, and major company announcements.\nBuild scalable systems, workflows, and tools (including AI-enabled solutions where relevant) to improve communication efficiency and quality.\nPartner closely with People and leadership teams to align messaging, priorities, and communication cadence across the organization.\n\nRequirements\n\n8–12 years of experience in internal or employee communications, ideally within fast-paced or mission-driven environments.\nProven experience defining communication strategy while also executing hands-on delivery across multiple channels and stakeholders.\nStrong background in executive communications, including advising senior leadership on tone, clarity, and messaging effectiveness.\nDemonstrated experience managing high-stakes communications such as restructures, organizational updates, or company-wide announcements.\nExceptional writing, storytelling, and editing skills with strong command of tone, voice, and narrative structure.\nAbility to influence cross-functional stakeholders and navigate complex organizational dynamics with clarity and diplomacy.\nBuilder mindset with strong problem-solving skills and comfort creating structure in ambiguous or evolving environments.\n\nBenefits\n\nCompetitive salary ranging from $145,000 to $218,000 annually, plus equity and performance-based compensation.\nComprehensive healthcare coverage including medical, dental, and vision insurance.\nFlexible remote-first work environment with strong work-life balance support.\nFlexible time-off policy and generous parental leave benefits.\nFinancial and wellness support programs, including mental health resources and lifestyle assistance.\nEquity opportunities providing long-term value and participation in company growth.\nProfessional development, learning programs, and career growth opportunities.\n\nHow Jobgether works:\nWe use an AI-powered matching process to ensure your application is reviewed quickly, objectively, and fairly against the role''s core requirements. Our system identifies the top-fitting candidates, and this shortlist is then shared directly with the hiring company. The final decision and next steps (interviews, assessments) are managed by their internal team.\nWe appreciate your interest and wish you the best!\n Why Apply Through Jobgether? \n \nData Privacy Notice: By submitting your application, you acknowledge that Jobgether will process your personal data to evaluate your candidacy and share relevant information with the hiring employer. This processing is based on legitimate interest and pre-contractual measures under applicable data protection laws (including GDPR). You may exercise your rights (access, rectification, erasure, objection) at any time.\n \n \n#LI-CL1','\n',char(10)),0,'senior (penalized) + CS/tech + internship','new','75932d4eb472c8fe4d3bee758135cb5b7614d16c8f3a1e6d63331bff521fe059','2026-06-02T08:12:26Z','global');
INSERT INTO "opportunities" ("id","type","title","organization","source","url","location","deadline","description","fit_score","fit_reason","status","dedup_hash","discovered_at","region") VALUES(128,'internship','Senior Manager, Internal Control and ESG','Jobgether','lever','https://jobs.lever.co/jobgether/4124bc94-4941-4877-8487-a5df5f6ae437','US',NULL,replace('This position is posted by Jobgether on behalf of a partner company. We are currently looking for a Senior Manager, Internal Control and ESG in United States.\n\nThis role sits at the intersection of governance, risk management, and sustainability, driving the evolution of internal control frameworks while shaping ESG reporting practices across a global organization. You will lead initiatives that strengthen control maturity, enhance transparency, and ensure compliance with financial and sustainability reporting requirements. Operating in a complex, cross-functional environment, you will partner with finance, sustainability, and operational teams to embed robust control processes and reliable ESG data practices. The position requires a strong blend of analytical rigor, transformation mindset, and stakeholder influence. You will also play a key role in enabling automation and digital tools that improve efficiency and data integrity. This is a high-impact leadership role where your work directly supports both regulatory confidence and long-term sustainability objectives.\n\nAccountabilities\n\nIn this role, you will lead the design, enhancement, and execution of internal control and ESG reporting frameworks, ensuring alignment with governance standards, regulatory expectations, and organizational transformation goals.\n\nLead internal control transformation initiatives to strengthen governance, risk management, and control maturity across the organization\nServe as subject matter expert for risk assessment, control design, implementation, testing, and continuous monitoring activities\nDrive improvement of control environments through automation, digital tools, and GRC system enhancements\nOversee control testing programs, KPI tracking, reporting processes, and remediation planning\nManage ESG reporting processes, ensuring accuracy, consistency, and alignment with regulatory and sustainability frameworks\nOwn ESG reporting systems and support data integrity, validation, and alignment between financial and non-financial disclosures\nPartner with sustainability, finance, and audit teams to support reporting cycles and external assurance activities\nLead cross-functional transformation projects, including planning, execution, change management, and stakeholder communication\nProvide regular updates to senior leadership, including progress tracking, risk escalation, and performance insights\n\nRequirements\nThis role requires strong expertise in internal controls, finance operations, and ESG reporting, combined with the ability to lead complex transformation initiatives in a global environment.\n\nMaster’s degree in Finance, Accounting, Business, or related field\nStrong background in internal controls, risk management, and finance processes\nExperience with ESG reporting frameworks and sustainability disclosure requirements\nProven track record leading cross-functional projects and transformation initiatives\nExperience with change management in complex, global organizations\nStrong project management, prioritization, and stakeholder engagement skills\nFamiliarity with finance systems, digital tools, and reporting technologies\nExperience with automation tools, GRC platforms, or process mining solutions is a plus\nStrong analytical thinking with the ability to simplify complex regulatory and operational challenges\nExcellent communication and influencing skills across technical and executive audiences\n\nBenefits\n\nHealth coverage options including medical, dental, and vision starting on day one\nFlexible HSA and FSA accounts for healthcare and dependent care expenses\n12 paid holidays annually\n15 vacation days plus 6 personal days\nPaid leave for jury duty and bereavement\n401(k) plan with immediate company match and full vesting from day one\nLife insurance and short- and long-term disability coverage\nPaid parental leave (16 weeks maternity / 4 weeks paternity)\nFlexible working policy supporting work-life balance and hybrid autonomy\n\nHow Jobgether works:\nWe use an AI-powered matching process to ensure your application is reviewed quickly, objectively, and fairly against the role''s core requirements. Our system identifies the top-fitting candidates, and this shortlist is then shared directly with the hiring company. The final decision and next steps (interviews, assessments) are managed by their internal team.\nWe appreciate your interest and wish you the best!\n Why Apply Through Jobgether? \n \nData Privacy Notice: By submitting your application, you acknowledge that Jobgether will process your personal data to evaluate your candidacy and share relevant information with the hiring employer. This processing is based on legitimate interest and pre-contractual measures under applicable data protection laws (including GDPR). You may exercise your rights (access, rectification, erasure, objection) at any time.\n \n \n#LI-CL1','\n',char(10)),2,'senior (penalized) + CS/tech + internship','new','209b2d05f9bd62000a669408c567c60350fa1733177ced391f5ee925c0246910','2026-06-02T08:12:26Z','global');
INSERT INTO "opportunities" ("id","type","title","organization","source","url","location","deadline","description","fit_score","fit_reason","status","dedup_hash","discovered_at","region") VALUES(190,'internship','Graduate Software Engineer, Open Source and Linux, Canonical Ubuntu','Jobgether','lever','https://jobs.lever.co/jobgether/3535bb01-285b-4bba-b823-cc7543639af6','India',NULL,replace('This position is posted by Jobgether on behalf of a partner company. We are currently looking for a Graduate Software Engineer, Open Source and Linux, Canonical Ubuntu in India.\n\nThis role offers an exceptional entry point into large-scale open source engineering, where you will contribute to systems that power cloud, AI, IoT, and enterprise infrastructure worldwide. You will work on deeply technical challenges spanning operating systems, developer tools, and distributed software used by millions of users. The environment is highly collaborative, remote-first, and globally distributed, with strong mentorship and regular in-person sprints. Engineers are encouraged to take ownership early, write production-grade code, and engage directly with users and open source communities. You will gain exposure across the full software stack, from low-level Linux components to modern cloud-native technologies. This position is ideal for high-performing graduates eager to build a long-term career in world-class open source engineering.\n\nAccountabilities\n\nYou will contribute to the design, development, and improvement of open source and commercial software products, working across diverse engineering teams and technology stacks. Your responsibilities will span building reliable systems, improving user experience, and engaging with global communities to deliver impactful software.\n\nWrite clean, efficient, and high-quality code in languages such as Python, Golang, Rust, C/C++, JavaScript, or Java, contributing to production systems at scale\nWork across the full stack of systems, including Ubuntu environments and broader Linux components\nParticipate in design discussions, global engineering sprints, and roadmap planning for product features and improvements\nCollaborate with users, contributors, and internal teams through code reviews, issue tracking, and community engagement\nSupport debugging, issue resolution, and customer-facing problem solving with a focus on reliability and performance\nDevelop strong awareness of software security, system design principles, and scalable architecture patterns\nContinuously learn and improve through mentorship, pair programming, and hands-on engineering challenges\n\nRequirements\nThis role requires strong academic foundations, a passion for software engineering, and a genuine interest in open source ecosystems. You should be motivated to learn, contribute, and grow in a fast-paced, high-expectation engineering environment.\n\nBachelor’s degree in Computer Science, Mathematics, Engineering, or a related STEM field with strong programming focus\nExcellent academic track record and evidence of high performance in technical studies or projects\nProficiency in at least one programming language such as Python, Rust, C/C++, Golang, JavaScript, or Java\nFamiliarity with Linux-based environments and interest in systems-level software development\nStrong analytical thinking, problem-solving ability, and attention to detail\nExperience with personal or academic software projects beyond coursework\nExcellent written and spoken English communication skills\nCuriosity, adaptability, accountability, and a strong desire to contribute to open source communities\nWillingness to travel internationally twice per year for global engineering events\n\nBenefits\n\nFully remote global-first work environment with structured team collaboration and mentorship\nAnnual learning and development budget to support technical growth and certifications\nCompetitive compensation with performance-based bonuses and annual salary reviews\nPaid annual leave, maternity and paternity leave, and wellness support programs\nOpportunities to attend international engineering sprints and collaborate in person with global teams\nRecognition programs and rewards for contributions and impact\nTravel support including upgrades and benefits for long-distance company events\nAccess to diverse, high-impact engineering projects across the open source ecosystem\n\nHow Jobgether works:\nWe use an AI-powered matching process to ensure your application is reviewed quickly, objectively, and fairly against the role''s core requirements. Our system identifies the top-fitting candidates, and this shortlist is then shared directly with the hiring company. The final decision and next steps (interviews, assessments) are managed by their internal team.\nWe appreciate your interest and wish you the best!\n Why Apply Through Jobgether? \n \nData Privacy Notice: By submitting your application, you acknowledge that Jobgether will process your personal data to evaluate your candidacy and share relevant information with the hiring employer. This processing is based on legitimate interest and pre-contractual measures under applicable data protection laws (including GDPR). You may exercise your rights (access, rectification, erasure, objection) at any time.\n \n \n#LI-CL1','\n',char(10)),100,'entry-level + CS/tech + location match + internship','new','833eca1de5e50ec331980b9f0ba4f2251728866ec26599a190c79a473944eb9d','2026-06-02T09:46:24Z','india');
