INSERT INTO "opportunities" ("id","type","title","organization","source","url","location","deadline","description","fit_score","fit_reason","status","dedup_hash","discovered_at","region") VALUES(1493,'internship','Sales Operations Intern, Italy','Airbnb','greenhouse','https://careers.airbnb.com/positions/7979270?gh_jid=7979270','Milan, Italy',NULL,replace('<div class= content-intro ><p><span style= font-family: helvetica, arial, sans-serif; font-size: 12pt; >Airbnb was born in 2007 when two hosts welcomed three guests to their San Francisco home, and has since grown to over 5 million hosts who have welcomed over 2 billion guest arrivals in almost every country across the globe. Every day, hosts offer unique stays and experiences that make it possible for guests to connect with communities in a more authentic way.</span></p></div><p><strong>The community you will join:</strong></p>\n<p>Airbnb is seeking a Sales Operations intern to join the Supply team based in Milan for a 12-month internship.</p>\n<p>The Supply Team at Airbnb works at the heart of the platform, driving host acquisition, retention, and growth across Italy and Southeast Europe. We are the engine behind expanding and optimizing Airbnb s host ecosystem — connecting people with unique spaces and enabling hosts to thrive through data-driven strategies, compelling outreach, and community engagement.</p>\n<p>We are looking for a proactive, analytically minded intern who is passionate about the travel and hospitality industry and eager to contribute to real business impact. You ll thrive in a fast-paced, collaborative environment and bring fresh energy and curiosity to everything you do.</p>\n<p> </p>\n<p><strong>The difference you will make:</strong></p>\n<ul>\n<li>Supporting the development of compelling sales pitches, narratives, and outreach scripts that effectively communicate Airbnb s value proposition to prospective hosts</li>\n<li>Partnering with the Sales Team to track key metrics and KPIs, generate performance reports, and surface actionable insights that help refine strategies and hit growth targets</li>\n<li>Learning from experienced team members how to craft and manage host communication campaigns, including email templates and educational resources that empower hosts to optimize their listings</li>\n<li>Supporting the coordination of virtual webinars and in-person events designed to engage the host community and drive platform adoption</li>\n<li>Contributing to ad-hoc cross-functional projects, bringing curiosity, flexibility, and a problem-solving attitude to a variety of business challenges as they evolve</li>\n</ul>\n<p> </p>\n<p><strong>The intern experience:</strong></p>\n<p>As an intern, you’ll be integrated into a team where you’ll contribute to challenging projects. Your manager, team, and our incredible employee community will strive to be superhosts to you during the summer. We provide the support, mentorship, fun, and real world experience needed to accelerate your learning and make a real impact on our product, as Airbnb revolutionizes connection, belonging, and travel. You can expect to:</p>\n<ul>\n<li>Collaborate with multiple team members to achieve project milestones</li>\n<li>Communicate with stakeholders across different teams to provide project updates</li>\n<li>Seek and provide feedback throughout the internship</li>\n<li>Actively participate in and contribute to the Supply team and broader Airbnb community</li>\n</ul>\n<p> </p>\n<p><strong>Your expertise:</strong></p>\n<ul>\n<li>A recent graduate completing a 12-month internship placement</li>\n<li>Fluency in English and Italian is required</li>\n<li>Strong organizational and time management skills, with the ability to juggle multiple tasks and priorities effectively in a fast-paced environment</li>\n<li>Analytical mindset: comfortable working with data to support sales strategies and identify opportunities for growth</li>\n<li>Goal-oriented and proactive, with a strong bias for action and the drive to take initiative and push through challenges</li>\n<li>Strong written and verbal communication skills, with the ability to engage confidently via email, phone, and in person</li>\n<li>Familiarity or interest in the hospitality or travel industry is a plus</li>\n<li>Exposure to CRM tools like Salesforce is a plus; willingness to learn is what matters most</li>\n</ul>\n<p> </p>\n<p><strong>Your Location:</strong></p>\n<p>This position is hybrid and you must be living in Milan and have work authorization for Italy to be eligible.</p>\n<p> </p>\n<p><strong>Our Commitment To Inclusion   Belonging:</strong></p>\n<p>Airbnb is committed to working with the broadest talent pool possible. We believe diverse ideas foster innovation and engagement, and allow us to attract creatively-led people, and to develop the best products, services and solutions. All qualified individuals are encouraged to apply.</p>\n<p>We strive to also provide a disability inclusive application and interview process. If you are a candidate with a disability and require reasonable accommodation in order to submit an application, please contact us at: reasonableaccommodations@airbnb.com. Please include your full name, the role you’re applying for and the accommodation necessary to assist you with the recruiting process. </p>\n<p>We ask that you only reach out to us if you are a candidate whose disability prevents you from being able to complete our online application.</p>\n<p><strong>Please submit all application materials in English.</strong></p>','\n',char(10)),NULL,NULL,'new','3201072595c798ed706c576811a143f88f488bc1a5201f6d52d7f0542afe8328','2026-06-04T11:24:55Z','global');
INSERT INTO "opportunities" ("id","type","title","organization","source","url","location","deadline","description","fit_score","fit_reason","status","dedup_hash","discovered_at","region") VALUES(1555,'internship','Provider Enrollment Internal Quality Analyst','Jobgether','lever','https://jobs.lever.co/jobgether/9d055ea2-3a7e-4f0b-8664-70dde140e2d4','US',NULL,replace('This position is posted by Jobgether on behalf of a partner company. We are currently looking for a Provider Enrollment Internal Quality Analyst in the United States.\n\nThis role focuses on ensuring the accuracy, integrity, and quality of provider enrollment and file maintenance processes within healthcare programs. You will play a key part in auditing operational data, identifying process gaps, and improving the overall quality of application processing workflows. Working in a detail-oriented and compliance-driven environment, you will conduct structured quality assurance reviews, support escalation handling, and contribute to root cause analysis efforts. The position requires strong analytical ability and consistency in meeting deadlines while ensuring data reliability and adherence to regulatory standards such as HIPAA. You will collaborate closely with leadership and cross-functional teams to resolve issues and enhance operational efficiency. This is an excellent opportunity for a quality-focused professional who thrives in structured, high-volume healthcare operations.\n\nAccountabilities\n\nYou will be responsible for conducting structured quality assurance reviews of provider enrollment and file maintenance processes, ensuring accuracy, compliance, and timely resolution of identified issues. Your work will help improve operational performance, reduce errors, and support continuous process improvement across healthcare enrollment functions.\n\nConduct targeted and specialized quality audits within defined timelines.\nReview, investigate, and respond to quality audit disputes, escalating issues when necessary.\nHandle escalation requests and ensure timely, accurate resolution.\nPerform data validation and ensure accuracy, consistency, and reliability across enrollment systems.\nConduct trend analysis and root cause investigations to identify training or process improvement needs.\nCollaborate with leadership and operational teams to address inquiries and improve workflow efficiency.\nRecommend enhancements to manual processes and support system or procedural improvements.\nMaintain strict confidentiality and compliance with HIPAA and other regulatory standards.\n\nRequirements\nThis role requires foundational experience in provider enrollment and quality assurance, combined with strong analytical skills and attention to detail. You should be comfortable working with data, managing deadlines, and communicating effectively in a structured healthcare operations environment.\n\nMinimum 6 months of combined experience in provider enrollment and internal quality assurance.\nStrong attention to detail with the ability to identify data inconsistencies and process gaps.\nExperience or familiarity with healthcare terminology and enrollment workflows (preferred).\nProficiency with Microsoft Office Suite, particularly Excel, Word, and Outlook.\nStrong analytical and problem-solving skills, including ability to perform trend analysis.\nAbility to manage multiple tasks and meet strict deadlines in a fast-paced environment.\nStrong communication skills for interacting with leadership and cross-functional teams.\nUnderstanding of confidentiality requirements, including HIPAA compliance.\n\nBenefits\n\nCompetitive salary range depending on location and experience ($44,500–$103,100 annually, varying by state)\nComprehensive medical, dental, vision, life, and disability coverage\n401(k) retirement savings plan with employer participation\nPaid holidays and paid time off\nBonus opportunities (where applicable)\nCareer development within a global professional services environment\nExposure to large-scale healthcare operations and quality assurance processes\nInclusive and diverse workplace culture with strong support for employee well-being\n\nHow Jobgether works:\nWe use an AI-powered matching process to ensure your application is reviewed quickly, objectively, and fairly against the role''s core requirements. Our system identifies the top-fitting candidates, and this shortlist is then shared directly with the hiring company. The final decision and next steps (interviews, assessments) are managed by their internal team.\nWe appreciate your interest and wish you the best!\n Why Apply Through Jobgether? \n \nData Privacy Notice: By submitting your application, you acknowledge that Jobgether will process your personal data to evaluate your candidacy and share relevant information with the hiring employer. This processing is based on legitimate interest and pre-contractual measures under applicable data protection laws (including GDPR). You may exercise your rights (access, rectification, erasure, objection) at any time.\n \n \n#LI-CL1','\n',char(10)),NULL,NULL,'new','6cbc5759a0015d3a960199ad51032b01429ed11a8a7e0305f22f25165403e6c4','2026-06-04T11:25:25Z','global');
INSERT INTO "opportunities" ("id","type","title","organization","source","url","location","deadline","description","fit_score","fit_reason","status","dedup_hash","discovered_at","region") VALUES(1563,'internship','Senior Internal Auditor','Jobgether','lever','https://jobs.lever.co/jobgether/48d98d67-6a3e-4270-b074-f18d61ebbc58','US',NULL,replace('This position is posted by Jobgether on behalf of a partner company. We are currently looking for a Senior Internal Auditor in United States.\n\nThis is a high-impact audit role focused on strengthening internal controls, compliance, and operational integrity across complex, highly regulated environments. You will lead end-to-end internal audit engagements, ensuring that contractual, regulatory, and customer obligations are consistently met while identifying risks and improvement opportunities. The role combines hands-on audit execution with advisory responsibilities, requiring strong analytical judgment and the ability to translate findings into clear corrective actions. You will work closely with cross-functional stakeholders and leadership teams to assess control effectiveness and drive remediation through structured CAPAs. Operating in a remote-first environment, you will play a key role in maintaining assurance over critical processes and compliance frameworks. This position is ideal for an audit professional who thrives in detail-driven, structured work while still engaging in strategic problem-solving.\n\nAccountabilities:\n\nIn this role, you will lead internal audit activities from planning through execution, ensuring compliance, control effectiveness, and continuous improvement across business processes.\n\nLead and execute internal audits assessing operational controls, compliance, and adherence to internal and external requirements.\nPlan, document, and manage full audit cycles, including fieldwork, data analysis, workpaper preparation, and reporting.\nIdentify, document, and track corrective and preventive actions (CAPAs), ensuring proper remediation and validation of control improvements.\nTest the design and effectiveness of internal controls and evaluate risk exposure across processes and systems.\nConduct interviews, walkthroughs, and testing procedures to identify compliance gaps and control weaknesses.\nCoordinate with internal stakeholders and external auditors to ensure alignment on findings and remediation efforts.\nPrepare detailed audit reports, executive summaries, and documentation clearly communicating findings and recommendations.\nSupport ad hoc advisory requests related to process improvements, policy updates, and control enhancements.\n\nRequirements:\nThis role requires a detail-oriented audit professional with strong knowledge of compliance frameworks, internal controls, and data-driven audit practices.\n\n3–5 years of experience in internal audit, compliance, or related assurance roles.\nBachelor’s degree or equivalent combination of education and professional experience.\nStrong knowledge of internal audit methodologies and compliance frameworks such as ISO standards, SOC 2, PCI DSS, and related regulatory requirements.\nExperience working with CAPA processes and audit lifecycle documentation.\nFamiliarity with accreditation or certification bodies (e.g., ANAB, A2LA, PCI SSC) is preferred.\nExperience using data analytics tools to identify trends, anomalies, and control gaps.\nStrong written and verbal communication skills with ability to present findings to both technical and non-technical stakeholders.\nExcellent critical thinking, organization, and project management abilities with strong attention to detail.\nRelevant certifications (CIA, CISA, CFE, CPA, or equivalent) are highly desirable.\n\nBenefits:\n\nFlexible 100% remote work environment.\nCompetitive compensation package.\nComprehensive health, dental, and vision insurance options.\nPaid parental leave and flexible time off policies.\nCertification, training, and professional development reimbursement.\nDigital mental health and wellbeing support programs.\nInclusive work culture with employee engagement and community initiatives.\n\nHow Jobgether works:\nWe use an AI-powered matching process to ensure your application is reviewed quickly, objectively, and fairly against the role''s core requirements. Our system identifies the top-fitting candidates, and this shortlist is then shared directly with the hiring company. The final decision and next steps (interviews, assessments) are managed by their internal team.\nWe appreciate your interest and wish you the best!\n Why Apply Through Jobgether? \n \nData Privacy Notice: By submitting your application, you acknowledge that Jobgether will process your personal data to evaluate your candidacy and share relevant information with the hiring employer. This processing is based on legitimate interest and pre-contractual measures under applicable data protection laws (including GDPR). You may exercise your rights (access, rectification, erasure, objection) at any time.\n \n \n#LI-CL1','\n',char(10)),NULL,NULL,'new','c89660cef3ce2a67938ecd66cbb0885345eaf0abd5cd7068fb7416c17681d667','2026-06-04T11:25:26Z','global');
